import React, { useCallback, useMemo, useState } from 'react';
import type { CustomerGroupDto } from '../../../services/master/models';
import {
  CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER,
  CUSTOMER_TYPE_LABELS,
  collectCustomerGroupAncestorIds,
  customerGroupNavRootsByMasterType,
  customerGroupRowCellStyle,
  customerGroupRowIndent,
  type CustomerGroupAnalysisType,
  type CustomerGroupTreeNode,
} from '../../../utils/customerGroupTree';
import styles from './CustomerGroupCascadeNav.module.css';

export type CustomerGroupNavSelection =
  | { kind: 'all' }
  | { kind: 'type'; customerType: CustomerGroupAnalysisType }
  | { kind: 'group'; customerGroupId: string };

type Props = {
  testIdPrefix: string;
  groups: CustomerGroupDto[];
  selection: CustomerGroupNavSelection;
  onSelect: (next: CustomerGroupNavSelection) => void;
  totalCount: number;
  typeCounts: Partial<Record<CustomerGroupAnalysisType, number>>;
};

/** Chevron width + flex gap — pad leaf rows so label aligns with expandable rows. */
const CHEVRON_COL_PX = 20;

function formatCount(value?: number): string {
  if (value == null || Number.isNaN(value)) return '0';
  return value > 999 ? '999+' : String(value);
}

export const CustomerGroupCascadeNav: React.FC<Props> = ({
  testIdPrefix,
  groups,
  selection,
  onSelect,
  totalCount,
  typeCounts,
}) => {
  const [expandedTypes, setExpandedTypes] = useState<Set<string>>(
    () => new Set(CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER),
  );
  const [expandedGroups, setExpandedGroups] = useState<Set<string>>(() => new Set());

  const treeByType = useMemo(
    () => customerGroupNavRootsByMasterType(groups),
    [groups],
  );

  const toggleType = useCallback((type: CustomerGroupAnalysisType) => {
    setExpandedTypes(prev => {
      const next = new Set(prev);
      if (next.has(type)) next.delete(type);
      else next.add(type);
      return next;
    });
  }, []);

  const toggleGroup = useCallback((groupId: string) => {
    setExpandedGroups(prev => {
      const next = new Set(prev);
      if (next.has(groupId)) next.delete(groupId);
      else next.add(groupId);
      return next;
    });
  }, []);

  const expandGroupPath = useCallback((groupId: string, customerType?: string | null) => {
    if (customerType) {
      setExpandedTypes(prev => new Set(prev).add(customerType));
    }
    setExpandedGroups(prev => {
      const next = new Set(prev);
      next.add(groupId);
      for (const ancestorId of collectCustomerGroupAncestorIds(groupId, groups)) {
        next.add(ancestorId);
      }
      return next;
    });
  }, [groups]);

  const selectGroup = useCallback((node: CustomerGroupTreeNode) => {
    expandGroupPath(node.customerGroupId, node.customerType);
    if (node.children.length > 0) {
      setExpandedGroups(prev => new Set(prev).add(node.customerGroupId));
    }
    onSelect({ kind: 'group', customerGroupId: node.customerGroupId });
  }, [expandGroupPath, onSelect]);

  const renderGroupNode = (node: CustomerGroupTreeNode): React.ReactNode => {
    const hasChildren = node.children.length > 0;
    const isExpanded = expandedGroups.has(node.customerGroupId);
    const isSelected =
      selection.kind === 'group' && selection.customerGroupId === node.customerGroupId;
    const indent = customerGroupRowIndent(node.level);
    const level1Style = node.level === 1 ? customerGroupRowCellStyle(node) : undefined;

    return (
      <div key={node.customerGroupId}>
        <button
          type="button"
          className={[styles.groupRow, isSelected ? styles.selected : ''].filter(Boolean).join(' ')}
          style={{
            paddingLeft: `${10 + indent + (hasChildren ? 0 : CHEVRON_COL_PX)}px`,
            ...level1Style,
          }}
          data-testid={`${testIdPrefix}-group-nav-${node.customerGroupId}`}
          onClick={e => {
            if ((e.target as HTMLElement).closest('[data-nav-chevron]')) return;
            selectGroup(node);
          }}
        >
          {hasChildren ? (
            <span
              className={styles.chevron}
              data-nav-chevron
              role="presentation"
              onClick={e => {
                e.preventDefault();
                e.stopPropagation();
                toggleGroup(node.customerGroupId);
              }}
            >
              <i className={`fas fa-chevron-${isExpanded ? 'down' : 'right'}`} aria-hidden />
            </span>
          ) : null}
          <span className={styles.groupCode}>{node.code}</span>
          <span className={styles.label} title={node.name}>{node.name}</span>
          <span className={styles.count}>{formatCount(node.customerCount)}</span>
        </button>
        {hasChildren && isExpanded ? (
          <div className={styles.children}>
            {node.children.map(child => renderGroupNode(child))}
          </div>
        ) : null}
      </div>
    );
  };

  return (
    <aside className={styles.aside} data-testid={`${testIdPrefix}-group-nav`}>
      <div className={styles.header}>Nhóm đối tượng</div>
      <div className={styles.scroll}>
        <button
          type="button"
          className={[styles.allRow, selection.kind === 'all' ? styles.selected : ''].filter(Boolean).join(' ')}
          data-testid={`${testIdPrefix}-group-nav-all`}
          onClick={() => onSelect({ kind: 'all' })}
        >
          <span className={styles.chevronPlaceholder} />
          <span className={styles.label}>Tất cả</span>
          <span className={styles.count}>{formatCount(totalCount)}</span>
        </button>

        {CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER.map(type => {
          const typeNodes = treeByType.get(type) ?? [];
          const hasTypeChildren = typeNodes.length > 0;
          const typeLabel = CUSTOMER_TYPE_LABELS[type] ?? type;
          const isTypeExpanded = expandedTypes.has(type);
          const isTypeSelected = selection.kind === 'type' && selection.customerType === type;
          const typeCount = typeCounts[type];

          return (
            <div key={type} className={styles.section}>
              <button
                type="button"
                className={[styles.typeRow, isTypeSelected ? styles.selected : ''].filter(Boolean).join(' ')}
                style={hasTypeChildren ? undefined : { paddingLeft: `${8 + CHEVRON_COL_PX}px` }}
                data-testid={`${testIdPrefix}-group-nav-type-${type}`}
                onClick={e => {
                  if ((e.target as HTMLElement).closest('[data-nav-chevron]')) return;
                  onSelect({ kind: 'type', customerType: type });
                }}
              >
                {hasTypeChildren ? (
                  <span
                    className={styles.chevron}
                    data-nav-chevron
                    role="presentation"
                    onClick={e => {
                      e.preventDefault();
                      e.stopPropagation();
                      toggleType(type);
                    }}
                  >
                    <i
                      className={`fas fa-chevron-${isTypeExpanded ? 'down' : 'right'}`}
                      aria-hidden
                    />
                  </span>
                ) : null}
                <span className={styles.label}>{typeLabel}</span>
                <span className={styles.count}>{formatCount(typeCount)}</span>
              </button>
              {isTypeExpanded && typeNodes.length > 0 ? (
                <div className={styles.children}>
                  {typeNodes.map(node => renderGroupNode(node))}
                </div>
              ) : null}
            </div>
          );
        })}
      </div>
    </aside>
  );
};
