import type { CustomerDto } from '../services/master/models';

/** Tree row indent — parity nhóm đối tượng. */
export const CUSTOMER_INDENT_PX = 16;

/** BE JSON `parentId` → normalized string id. */
export function normalizeCustomerDto(c: CustomerDto): CustomerDto {
  return {
    ...c,
    customerId: String(c.customerId),
    parentId: c.parentId ? String(c.parentId) : undefined,
  };
}

export function getCustomerParentId(c: CustomerDto): string | null {
  const id = c.parentId;
  return id ? String(id) : null;
}

const defaultSiblingCompare = (a: CustomerDto, b: CustomerDto) =>
  a.code.localeCompare(b.code, 'vi', { numeric: true });

/**
 * Flatten depth-first: cha → con (con ngay dưới cha, thụt lề).
 * Siblings sorted by `compareSiblings` (default: mã).
 */
export function flattenCustomerTree(
  items: CustomerDto[],
  compareSiblings?: (a: CustomerDto, b: CustomerDto) => number,
): CustomerDto[] {
  const compare = compareSiblings ?? defaultSiblingCompare;
  const normalized = items.map(normalizeCustomerDto);
  const idSet = new Set(normalized.map(c => c.customerId));

  const childrenOf = new Map<string | null, CustomerDto[]>();
  for (const c of normalized) {
    let parentKey = getCustomerParentId(c);
    if (parentKey && !idSet.has(parentKey)) {
      parentKey = null;
    }
    const list = childrenOf.get(parentKey);
    if (list) list.push(c);
    else childrenOf.set(parentKey, [c]);
  }

  for (const list of childrenOf.values()) {
    list.sort(compare);
  }

  const out: CustomerDto[] = [];
  const visit = (parentId: string | null) => {
    for (const c of childrenOf.get(parentId) ?? []) {
      out.push(c);
      visit(c.customerId);
    }
  };
  visit(null);
  return out;
}

/** Depth from parent chain within loaded rows (entity has no BE `level`). */
export function buildCustomerDepthMap(items: CustomerDto[]): Map<string, number> {
  const normalized = items.map(normalizeCustomerDto);
  const byId = new Map(normalized.map(c => [c.customerId, c]));
  const cache = new Map<string, number>();

  const depthOf = (id: string, visiting = new Set<string>()): number => {
    if (cache.has(id)) return cache.get(id)!;
    if (visiting.has(id)) {
      cache.set(id, 1);
      return 1;
    }
    visiting.add(id);
    const c = byId.get(id);
    if (!c) {
      cache.set(id, 1);
      return 1;
    }
    const parentId = getCustomerParentId(c);
    if (!parentId || !byId.has(parentId)) {
      cache.set(id, 1);
      return 1;
    }
    const d = depthOf(parentId, visiting) + 1;
    cache.set(id, d);
    return d;
  };

  for (const c of normalized) depthOf(c.customerId);
  return cache;
}

export function customerRowDepth(row: CustomerDto, depthMap: Map<string, number>): number {
  return depthMap.get(row.customerId) ?? 1;
}
